<template><div class="page-container"><el-card><template #header><span>退货单</span><el-button type="primary" size="small" style="float:right">新建退货单</el-button></template><el-form :inline="true"><el-form-item label="状态"><el-select v-model="f.status" clearable><el-option v-for="s in ['PENDING','PROCESSED','PURCHASED','CANCELLED']" :key="s" :label="s" :value="s"/></el-select></el-form-item><el-form-item label="退货类型"><el-select v-model="f.return_type" clearable><el-option label="扣款" value="DEDUCT"/><el-option label="补货" value="REPLENISH"/></el-select></el-form-item><el-form-item><el-input v-model="f.search" placeholder="退货单号" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="return_no" label="退货单号" width="150"/><el-table-column prop="return_type" label="类型" width="80"/><el-table-column label="供应商" width="120"><template #default="{ row }">{{ row.supplier_name||r.supplier }}</template></el-table-column><el-table-column prop="total_amount" label="退货金额" width="120"/><el-table-column prop="status" label="状态" width="100"/><el-table-column prop="return_date" label="退货日期" width="120"/><el-table-column label="操作" width="150"><template #default="{ row }"><el-button size="small" @click="handleDetail(r)">详情</el-button><el-button size="small" type="warning">审核</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { returnOrderApi } from '@/api/purchase'; import { ElMessage } from 'element-plus'
const f = reactive({ status: '', return_type: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await returnOrderApi.list({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
function handleDetail(r) { ElMessage.info(`详情: ${r.return_no}`) }
onMounted(load)
</script>
